void SaveResultFromGrid(bool decision)
{
    string baseDir = GlobalValues.GetDataPath();
    string todayPath = Path.Combine(baseDir, DateTime.Now.ToString("yyyy"), DateTime.Now.ToString("MM"), DateTime.Now.ToString("dd"));
    Directory.CreateDirectory(todayPath);

    string serial = "serial";
    string resultTag = (decision) ? "OK" : "NG";
    string timeStamp = DateTime.Now.ToString("yyyyMMdd_HHmmss");
    string fileName = $"{timeStamp}-{resultTag}_{jig.Jig_ID}_{serial}.csv";
    string fullPath = Path.Combine(todayPath, fileName);

    if (!File.Exists(fullPath))
    {
        using (StreamWriter sw = new StreamWriter(fullPath, false, Encoding.UTF8))
        {
            // 1. 컬럼 헤더 저장
            string[] headers = dataGridView1.Columns
                .Cast<DataGridViewColumn>()
                .Select(col => col.HeaderText)
                .ToArray();
            sw.WriteLine(string.Join(",", headers));  // ← 탭 대신 쉼표 사용

            // 2. 행 데이터 저장
            foreach (DataGridViewRow row in dataGridView1.Rows)
            {
                if (row.IsNewRow) continue;

                string[] cells = row.Cells
                    .Cast<DataGridViewCell>()
                    .Select(cell => cell.Value?.ToString()?.Replace(",", "") ?? "")  // 쉼표 제거 (CSV 충돌 방지)
                    .ToArray();

                sw.WriteLine(string.Join(",", cells));  // ← 탭 대신 쉼표 사용
            }
        }
    }
}

